// Format weekly summary text for webhook notification.
// Hardened: wraps in try/catch to prevent 'Unknown error' crashes on bad API responses.
try {
  const input = $input.first();
  if (!input || !input.json) {
    console.warn('[weekly-summary] No response from /digest endpoint — returning empty summary.');
    return [{ json: { summaryText: 'Weekly summary unavailable — digest endpoint did not respond.', error: 'no_response' } }];
  }
  const digest = input.json.digest || input.json;
  const funnel = digest.funnel || {};
  const ig = digest.ingestion || {};
  const summaryText = [
    '📊 Weekly Job Search Summary',
    '',
    `New this week: ${digest.newThisWeek || 0}`,
    `Pending approval: ${funnel.pendingApproval || 0}`,
    `Applied: ${funnel.applied || 0}`,
    `Interviewing: ${funnel.interviewing || 0}`,
    `Offers: ${funnel.offers || 0}`,
    '',
    `Ingestion: ${ig.newJobsIngested || 0} new jobs, ${ig.failures || 0} failures this week`,
  ].join('\n');
  return [{ json: { ...digest, summaryText } }];
} catch (err) {
  console.error('[weekly-summary] Format error:', err.message || String(err));
  return [{ json: { summaryText: 'Weekly summary error — see n8n logs.', error: err.message || String(err) } }];
}
